import json

with open('/tmp/cat_report.json', 'r') as f:
    raw = f.read()

# The response is multiple JSON objects concatenated
lines = raw.strip().split('\n')
data_str = None
for line in lines:
    if line.startswith('data: '):
        d = json.loads(line[6:])
        if 'result' in d:
            content = d['result']['content']
            if content and len(content) > 0:
                data_str = content[0]['text']
                break

if data_str:
    products = json.loads(data_str)
    top100 = products.get('Top100商品', [])
    print(f'Total products: {len(top100)}')
    for i, p in enumerate(top100[:3]):
        print(f"\n--- Product {i+1} ---")
        for k, v in p.items():
            print(f"  {k}: {v}")
else:
    print("No data found")
EOF

