import json

with open('/tmp/cat_report.json', 'r') as f:
    raw = f.read()

lines = raw.strip().split('\n')
for line in lines[:5]:
    if line.startswith('data: '):
        d = json.loads(line[6:])
        if 'result' in d:
            content = d['result']['content']
            if content and len(content) > 0:
                data_str = content[0]['text']
                products = json.loads(data_str)
                print("Keys:", list(products.keys()))
                for k, v in products.items():
                    if k != 'Top100商品':
                        print(f"{k}: {str(v)[:200]}")
                    else:
                        print(f"Top100商品 count: {len(v) if isinstance(v, list) else v}")
                break
